CRYPTO_HEADER = b"PKEN"
PBKDF2_ITERATIONS = 200000
SALT_LEN = 16
MAC_LEN = 32


def _keystream(key, length):
    out = bytearray()
    counter = 0
    while len(out) < length:
        out.extend(hashlib.sha256(key + counter.to_bytes(8, "big")).digest())
        counter += 1
    return bytes(out[:length])


def _decrypt_payload(blob, password):
    if blob[:4] != CRYPTO_HEADER:
        raise ValueError("payload is not encrypted (missing PKEN header)")
    salt = blob[4:4 + SALT_LEN]
    expected_mac = blob[4 + SALT_LEN:4 + SALT_LEN + MAC_LEN]
    ct = blob[4 + SALT_LEN + MAC_LEN:]
    derived = hashlib.pbkdf2_hmac(
        "sha256", password.encode("utf-8"), salt, PBKDF2_ITERATIONS, 64,
    )
    enc_key, mac_key = derived[:32], derived[32:]
    actual_mac = hmac.new(mac_key, salt + ct, "sha256").digest()
    if not hmac.compare_digest(expected_mac, actual_mac):
        raise ValueError("wrong password or corrupted bundle")
    ks = _keystream(enc_key, len(ct))
    return bytes(a ^ b for a, b in zip(ct, ks))


def main():
    ap = argparse.ArgumentParser(description="Extract cp_map_feedback bundle.")
    ap.add_argument("--out", default=".", help="Extraction directory (default: current dir)")
    ap.add_argument("--list", action="store_true", help="List bundled files and exit")
    ap.add_argument(
        "--password",
        help="Bundle password (else BUNDLE_PASSWORD env var, else prompt). "
             "Ignored if bundle is unencrypted.",
    )
    args = ap.parse_args()

    raw = base64.b64decode(DATA)

    if raw[:4] == CRYPTO_HEADER:
        password = args.password
        if password is None:
            password = os.environ.get("BUNDLE_PASSWORD")
        if password is None:
            interactive = sys.stdin.isatty() and sys.stdout.isatty()
            if interactive:
                try:
                    password = getpass.getpass("Bundle password: ")
                except (EOFError, KeyboardInterrupt):
                    print("\nAborted.", file=sys.stderr)
                    return 1
            else:
                print(
                    "ERROR: encrypted bundle, password required. "
                    "Pass via --password or BUNDLE_PASSWORD env.",
                    file=sys.stderr,
                )
                return 2
        if not password:
            print("ERROR: encrypted bundle requires a non-empty password.", file=sys.stderr)
            return 2
        try:
            zip_bytes = _decrypt_payload(raw, password)
        except ValueError as e:
            print(f"ERROR: {e}", file=sys.stderr)
            return 3
    else:
        zip_bytes = raw

    z = zipfile.ZipFile(io.BytesIO(zip_bytes))

    if args.list:
        for name in z.namelist():
            print(name)
        return 0

    out = Path(args.out).resolve()
    out.mkdir(parents=True, exist_ok=True)
    z.extractall(out)
    print(f"Extracted {len(z.namelist())} files to {out}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
